from datetime import datetime

CITIES = [
    {
        "name": "Tallinn",
        "country": "Estonia",
        "region": "Northern Europe",
        "climate": "continental-maritime",
        "peakHours": [11, 12, 13, 18, 19, 20, 21],
        "thresholds": {
            "heavyRain": 5,
            "extremeSnow": 10,
            "extremeCold": -15,
            "extremeHeat": 30,
            "highWind": 60,
            "freezingTemp": 0,
        },
    },
    {
        "name": "Bucharest",
        "country": "Romania",
        "region": "Eastern Europe",
        "climate": "continental",
        "peakHours": [11, 12, 13, 18, 19, 20, 21],
        "thresholds": {
            "heavyRain": 10,
            "extremeSnow": 3,
            "extremeCold": -10,
            "extremeHeat": 38,
            "highWind": 50,
            "freezingTemp": 0,
        },
    },
    {
        "name": "Lisbon",
        "country": "Portugal",
        "region": "Southern Europe",
        "climate": "mediterranean",
        "peakHours": [12, 13, 14, 19, 20, 21, 22],
        "thresholds": {
            "heavyRain": 15,
            "extremeSnow": 0.1,
            "extremeCold": 5,
            "extremeHeat": 40,
            "highWind": 50,
            "freezingTemp": 2,
        },
    },
    {
        "name": "Nairobi",
        "country": "Kenya",
        "region": "Africa",
        "climate": "tropical-highland",
        "peakHours": [11, 12, 13, 18, 19, 20, 21],
        "thresholds": {
            "heavyRain": 20,
            "extremeSnow": 0.1,
            "extremeCold": 10,
            "extremeHeat": 32,
            "highWind": 40,
            "freezingTemp": 12,
        },
    },
]

def parse_dt(time_value):
    return datetime.fromisoformat(time_value.replace("Z", "+00:00"))

def round_1(value):
    return round(value, 1)

def format_window(times):
    if not times:
        return "Next 24-48 hours"

    start = parse_dt(times[0])
    end = parse_dt(times[-1])

    if start.date() == end.date():
        return f"{start.strftime('%a %d %b %H:%M')} - {end.strftime('%H:%M')}"

    return f"{start.strftime('%a %d %b %H:%M')} - {end.strftime('%a %d %b %H:%M')}"

def safe_get(values, index, default=0):
    try:
        value = values[index]
        return default if value is None else value
    except Exception:
        return default

def analyze_weather_alerts(weather_data):
    all_alerts = []

    for i, city in enumerate(CITIES):
        data = weather_data[i] if isinstance(weather_data, list) and i < len(weather_data) else weather_data

        if not data or "hourly" not in data:
            continue

        hourly = data["hourly"]
        times = hourly.get("time", [])

        if not times:
            continue

        temperatures = hourly.get("temperature_2m", [])
        precipitation = hourly.get("precipitation", [])
        snowfall = hourly.get("snowfall", [])
        windspeed = hourly.get("windspeed_10m", [])
        weather_codes = hourly.get("weathercode", [])
        humidity_values = hourly.get("relative_humidity_2m", [])

        max_precip = 0
        max_snow = 0
        min_temp = 100
        max_temp = -100
        max_wind = 0
        total_precip = 0
        peak_hour_issues = []
        bad_weather_times = []
        worst_weather_codes = []

        thresholds = city["thresholds"]

        for h in range(len(times)):
            temp = safe_get(temperatures, h, 0)
            precip = safe_get(precipitation, h, 0)
            snow = safe_get(snowfall, h, 0)
            wind = safe_get(windspeed, h, 0)
            code = safe_get(weather_codes, h, 0)
            hour = parse_dt(times[h]).hour

            max_precip = max(max_precip, precip)
            max_snow = max(max_snow, snow)
            min_temp = min(min_temp, temp)
            max_temp = max(max_temp, temp)
            max_wind = max(max_wind, wind)
            total_precip += precip
            worst_weather_codes.append(code)

            is_bad_hour = (
                precip >= thresholds["heavyRain"] * 0.5
                or snow >= thresholds["extremeSnow"] * 0.5
                or wind >= thresholds["highWind"] * 0.7
                or temp <= thresholds["extremeCold"]
                or temp >= thresholds["extremeHeat"]
                or code >= 95
                or (temp <= thresholds["freezingTemp"] and precip > 0)
            )

            if is_bad_hour:
                bad_weather_times.append(times[h])

            if hour in city["peakHours"] and is_bad_hour:
                peak_hour_issues.append(times[h])

        conditions = []
        severity = 0

        if max_precip >= thresholds["heavyRain"]:
            conditions.append({
                "type": "HEAVY_RAIN",
                "value": round_1(max_precip),
                "unit": "mm/h",
                "threshold": thresholds["heavyRain"],
            })
            severity += 3

        if total_precip > thresholds["heavyRain"] * 3:
            conditions.append({
                "type": "SUSTAINED_RAIN",
                "value": round_1(total_precip),
                "unit": "mm total",
                "threshold": thresholds["heavyRain"] * 3,
            })
            severity += 2

        if max_snow >= thresholds["extremeSnow"]:
            conditions.append({
                "type": "SNOW",
                "value": round_1(max_snow),
                "unit": "cm",
                "threshold": thresholds["extremeSnow"],
            })
            severity += 4

        if min_temp <= thresholds["extremeCold"]:
            conditions.append({
                "type": "EXTREME_COLD",
                "value": round_1(min_temp),
                "unit": "°C",
                "threshold": thresholds["extremeCold"],
            })
            severity += 3

        if max_temp >= thresholds["extremeHeat"]:
            conditions.append({
                "type": "EXTREME_HEAT",
                "value": round_1(max_temp),
                "unit": "°C",
                "threshold": thresholds["extremeHeat"],
            })
            severity += 3

        if max_wind >= thresholds["highWind"]:
            conditions.append({
                "type": "HIGH_WIND",
                "value": round_1(max_wind),
                "unit": "km/h",
                "threshold": thresholds["highWind"],
            })
            severity += 2

        if min_temp <= thresholds["freezingTemp"] and max_precip > 0:
            conditions.append({
                "type": "FREEZING_RAIN_RISK",
                "value": round_1(min_temp),
                "unit": "°C with precipitation",
            })
            severity += 4

        if any(code >= 95 for code in worst_weather_codes):
            conditions.append({
                "type": "THUNDERSTORM",
                "value": "WMO code 95+",
            })
            severity += 3

        if peak_hour_issues:
            severity += 2

        severity = min(severity, 10)

        if conditions:
            if severity >= 7:
                classification = "CRITICAL"
            elif severity >= 5:
                classification = "HIGH"
            elif severity >= 3:
                classification = "MEDIUM"
            else:
                classification = "LOW"

            all_alerts.append({
                "city": city["name"],
                "country": city["country"],
                "region": city["region"],
                "climate": city["climate"],
                "severity": severity,
                "classification": classification,
                "conditions": conditions,
                "peakHourIssues": len(peak_hour_issues),
                "summary": {
                    "maxPrecip": round_1(max_precip),
                    "totalPrecip": round_1(total_precip),
                    "maxSnow": round_1(max_snow),
                    "minTemp": round_1(min_temp),
                    "maxTemp": round_1(max_temp),
                    "maxWind": round_1(max_wind),
                    "humidity": max(humidity_values) if humidity_values else None,
                },
                "forecastPeriod": {
                    "from": times[0],
                    "to": times[-1],
                    "riskWindow": format_window(bad_weather_times),
                },
            })

    all_alerts.sort(key=lambda x: x["severity"], reverse=True)
    significant_alerts = [a for a in all_alerts if a["severity"] >= 3]

    return {
        "alerts": significant_alerts,
        "totalCities": 4,
        "alertCount": len(significant_alerts),
        "timestamp": datetime.utcnow().isoformat() + "Z",
    }

items = _input.all()
weather_data = [item["json"] for item in items]
result = analyze_weather_alerts(weather_data)
return [{"json": result}]

import json
import re
from datetime import datetime

input_data = _input.item["json"]
if hasattr(input_data, "to_py"):
    input_data = input_data.to_py()

# n8n HTTP node may return only Gemini output. For fallback, this node also supports
# existing newAlerts if your n8n version preserves paired item data. If not, AI parse errors
# are still returned clearly and can be handled during demo/write-up.
fallback_alerts = input_data.get("newAlerts", [])
ai_alerts = []
ai_text = ""

try:
    ai_text = input_data["candidates"][0]["content"]["parts"][0]["text"]
    cleaned = re.sub(r"```json\n?", "", ai_text)
    cleaned = re.sub(r"```\n?", "", cleaned).strip()
    ai_alerts = json.loads(cleaned)
except Exception:
    if fallback_alerts:
        for alert in fallback_alerts:
            classification = alert.get("classification", "MEDIUM")
            if classification == "CRITICAL":
                severity_label = "🔴 Critical"
            elif classification == "HIGH":
                severity_label = "🚨 Urgent"
            else:
                severity_label = "⚠️ Heads-up"

            condition_names = ", ".join([
                c.get("type", "").replace("_", " " ).title()
                for c in alert.get("conditions", [])
            ])

            ai_alerts.append({
                "city": alert.get("city"),
                "severity_label": severity_label,
                "headline": condition_names or "Weather risk detected",
                "impact": "Delivery delays and courier supply disruption possible.",
                "actions": [
                    "Monitor courier acceptance rate",
                    "Extend ETA buffers if needed",
                    "Notify local operations team"
                ],
                "timing": alert.get("forecastPeriod", {}).get("riskWindow", "Next 24-48 hours"),
                "confidence": "MEDIUM",
                "reason": "Rule-based fallback triggered due to AI failure."
            })
    else:
        return [{
            "json": {
                "error": "Failed to parse Gemini response and no fallback alerts were available",
                "raw": input_data
            }
        }]

now = datetime.utcnow()
date_str = now.strftime("%A, %B %d, %Y")
time_str = now.strftime("%H:%M")

blocks = [
    {
        "type": "header",
        "text": {
            "type": "plain_text",
            "text": "Bolt Food Weather Operations Alert",
            "emoji": True
        }
    },
    {
        "type": "context",
        "elements": [
            {
                "type": "mrkdwn",
                "text": f"*Date:* {date_str} | *Time:* {time_str} UTC | *Forecast:* next 24-48h | *Next check:* in 6 hours"
            }
        ]
    },
    {"type": "divider"}
]

for alert in ai_alerts:
    actions = alert.get("actions", [])
    action_text = "\n".join([f"{i + 1}. {a}" for i, a in enumerate(actions)])

    blocks.append({
        "type": "section",
        "text": {
            "type": "mrkdwn",
            "text": f"*{alert.get('city')}* — {alert.get('severity_label')}\n*{alert.get('headline')}*"
        }
    })

    blocks.append({
        "type": "section",
        "text": {
            "type": "mrkdwn",
            "text": (
                f"*Impact:* {alert.get('impact')}\n\n"
                f"*Timing:* {alert.get('timing')}\n"
                f"*Confidence:* {alert.get('confidence')}\n"
                f"*Reason:* {alert.get('reason')}"
            )
        }
    })

    blocks.append({
        "type": "section",
        "text": {
            "type": "mrkdwn",
            "text": f"*Recommended Actions:*\n{action_text}"
        }
    })

    blocks.append({"type": "divider"})

blocks.append({
    "type": "context",
    "elements": [
        {
            "type": "mrkdwn",
            "text": "_Generated by Bolt Food Weather Intelligence | AI-assisted operational guidance | Data: Open-Meteo_"
        }
    ]
})

city_names = ", ".join([a.get("city", "") for a in ai_alerts])

return [{
    "json": {
        "blocks": blocks,
        "text": f"Weather Alert: {city_names}"
    }
}]
